243	func storeV2FetchPack(store storer.Storer, r io.Reader, verbose bool) error {
244		reader := NewPacketReader(r)
245		for {
246			kind, payload, err := reader.ReadPacket()
247			if err != nil {
248				if errors.Is(err, io.EOF) {
249					return nil
250				}
251				return fmt.Errorf("decode protocol v2 fetch response: %w", err)
252			}
253			switch kind {
254			case PacketFlush:
255				return nil
256			case PacketDelim, PacketResponseEnd:
257				continue
258			case PacketData:
259				line := string(payload)
260				switch line {
261				case "packfile\n":
262					demux := sideband.NewDemuxer(sideband.Sideband64k, reader.BufReader())
263					demux.Progress = progressSink(verbose, "source: ")
264					if err := packfile.UpdateObjectStorage(store, demux); err != nil {
265						return fmt.Errorf("update object storage: %w", err)
266					}
267					return nil
268				case "acknowledgments\n", "shallow-info\n":
269					if err := SkipSection(reader); err != nil {
270						return err
271					}
272				default:
273					return fmt.Errorf("unexpected protocol v2 fetch section %q", strings.TrimSpace(line))
274				}
275			}
276		}
277	}
