317	// buildV1UploadPackBody encodes a v1 upload-pack request body for stateless-rpc HTTP.
318	func buildV1UploadPackBody(
319		adv *packp.AdvRefs,
320		desired map[plumbing.ReferenceName]DesiredRef,
321		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
322		includeTags bool,
323		verbose bool,
324	) ([]byte, *capability.List, error) {
325		wants := collectWants(desired)
326		haves := SortedUniqueHashes(refValues(targetRefs))
327		if len(wants) == 0 {
328			return nil, nil, git.NoErrAlreadyUpToDate
329		}
330	
331		req := packp.NewUploadRequest()
332		req.Wants = wants
333		if !verbose && adv.Capabilities.Supports(capability.NoProgress) {
334			if err := req.Capabilities.Set(capability.NoProgress); err != nil {
335				return nil, nil, fmt.Errorf("set capability: %w", err)
336			}
337		}
338		if includeTags && adv.Capabilities.Supports(capability.IncludeTag) {
339			if err := req.Capabilities.Set(capability.IncludeTag); err != nil {
340				return nil, nil, fmt.Errorf("set capability: %w", err)
341			}
342		}
343		// Prefer sideband64k over sideband (issue #4).
344		if sb := PreferredSideband(adv.Capabilities); sb != "" {
345			if err := req.Capabilities.Set(sb); err != nil {
346				return nil, nil, fmt.Errorf("set capability: %w", err)
347			}
348		}
349		if adv.Capabilities.Supports(capability.OFSDelta) {
350			if err := req.Capabilities.Set(capability.OFSDelta); err != nil {
351				return nil, nil, fmt.Errorf("set capability: %w", err)
352			}
353		}
354		// NOTE: we intentionally do not request capability.ThinPack. The relayed
355		// pack must stay self-contained because callers (e.g. replicate) forward
356		// it to receive-pack servers that may advertise "no-thin".
357		// planner.SupportsReplicateRelay depends on this invariant — if you add
358		// thin-pack support here, update that check to gate on target NoThin.
359	
360		var buf bytes.Buffer
361		if err := req.Encode(&buf); err != nil {
362			return nil, nil, fmt.Errorf("encode upload-request: %w", err)
363		}
364		uphav := &packp.UploadHaves{Haves: haves, Done: true}
365		if err := uphav.Encode(&buf); err != nil {
366			return nil, nil, fmt.Errorf("encode upload-haves: %w", err)
367		}
368		return buf.Bytes(), req.Capabilities, nil
369	}
