115		)
116		for _, h := range sortedHaves {
117			cmdArgs = append(cmdArgs, "have "+h.String())
118		}
119		cmdArgs = append(cmdArgs, "done")
120	
121		body, err := EncodeCommand("fetch", s.V2Caps.RequestCapabilities(), cmdArgs)
122		if err != nil {
