192	func fetchPackV2(
193		ctx context.Context,
194		conn *Conn,
195		caps *V2Capabilities,
196		desired map[plumbing.ReferenceName]DesiredRef,
197		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
198		verbose bool,
199	) (io.ReadCloser, error) {
200		wants := collectWants(desired)
201		haves := SortedUniqueHashes(refValues(targetRefs))
202		if len(wants) == 0 {
203			return nil, git.NoErrAlreadyUpToDate
204		}
205	
206		cmdArgs := make([]string, 0, len(wants)+len(haves)+4)
207		// NOTE: no "thin-pack" argument. The relayed pack must stay
208		// self-contained so callers (e.g. replicate) can forward it to
209		// receive-pack servers that may advertise "no-thin". See
210		// planner.SupportsReplicateRelay for the matching invariant.
211		cmdArgs = append(cmdArgs, "ofs-delta")
212		if !verbose {
213			cmdArgs = append(cmdArgs, "no-progress")
214		}
215		// Only request include-tag if the server supports it (issue #6).
216		if hasTag(desired) && caps.FetchSupports("include-tag") {
217			cmdArgs = append(cmdArgs, "include-tag")
218		}
219		for _, h := range wants {
220			cmdArgs = append(cmdArgs, "want "+h.String())
221		}
222		for _, h := range haves {
223			cmdArgs = append(cmdArgs, "have "+h.String())
224		}
225		cmdArgs = append(cmdArgs, "done")
226	
227		body, err := EncodeCommand("fetch", caps.RequestCapabilities(), cmdArgs)
228		if err != nil {
229			return nil, err
230		}
231		reader, err := PostRPCStream(ctx, conn, transport.UploadPackService, body, true, "upload-pack fetch")
232		if err != nil {
233			return nil, err
234		}
235		packStream, err := openV2PackStream(reader, verbose)
236		if err != nil {
237			_ = reader.Close()
238			return nil, err
239		}
240		return packStream, nil
241	}
